import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Login = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState('');
    const { login } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault(); // КРИТИЧНО: останавливает перезагрузку
        setError('');

        try {
            await login(username.trim(), password.trim());
            navigate('/products');
        } catch (err) {
            // Берем текст ошибки из бэкенда или пишем свой
            setError(err.response?.data?.error || 'Неверный логин или пароль');
        }
    };

    return (
        <div style={styles.container}>
            <div style={styles.card}>
                <h2 style={styles.title}>Вход в систему</h2>

                {/* Твое текстовое окошко */}
                <div style={styles.adminBox}>
                    <div style={{fontSize: '12px', color: '#666'}}>Данные админа:</div>
                    <strong>admin</strong> / <strong>admin123</strong>
                </div>

                {error && <div style={styles.error}>{error}</div>}

                <form onSubmit={handleSubmit}>
                    <div style={styles.formGroup}>
                        <label style={styles.label}>Логин</label>
                        <input
                            style={styles.input}
                            type="text"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            required
                        />
                    </div>

                    <div style={styles.formGroup}>
                        <label style={styles.label}>Пароль</label>
                        <div style={styles.passWrapper}>
                            <input
                                style={{ ...styles.input, flex: 1 }}
                                type={showPassword ? 'text' : 'password'}
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                            />
                            {/* type="button" чтобы не обновлялась страница! */}
                            <button
                                type="button" 
                                onClick={() => setShowPassword(!showPassword)}
                                style={styles.eyeBtn}
                            >
                                {showPassword ? '🙈' : '👁️'}
                            </button>
                        </div>
                    </div>

                    <button type="submit" style={styles.submitBtn}>Войти</button>
                </form>

                <p style={{marginTop: '15px', fontSize: '14px'}}>
                    Нет аккаунта? <Link to="/register" style={{color: '#007AFF'}}>Регистрация</Link>
                </p>
            </div>
        </div>
    );
};

const styles = {
    container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', backgroundColor: '#f0f2f5' },
    card: { backgroundColor: '#fff', padding: '30px', borderRadius: '20px', boxShadow: '0 8px 24px rgba(0,0,0,0.1)', width: '320px', textAlign: 'center' },
    title: { marginBottom: '20px', color: '#333' },
    adminBox: { backgroundColor: '#e7f3ff', padding: '10px', borderRadius: '10px', marginBottom: '20px', fontSize: '14px', border: '1px solid #bde0ff' },
    formGroup: { marginBottom: '15px', textAlign: 'left' },
    label: { display: 'block', marginBottom: '5px', fontWeight: '600', fontSize: '14px', color: '#666' },
    input: { padding: '10px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '16px', outline: 'none' },
    passWrapper: { display: 'flex', gap: '5px' },
    eyeBtn: { padding: '0 10px', border: '1px solid #ddd', borderRadius: '8px', backgroundColor: '#fff', cursor: 'pointer', fontSize: '18px' },
    submitBtn: { width: '100%', padding: '12px', borderRadius: '8px', border: 'none', backgroundColor: '#007AFF', color: '#fff', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px' },
    error: { color: 'red', backgroundColor: '#fff0f0', padding: '8px', borderRadius: '8px', marginBottom: '15px', fontSize: '13px' }
};

export default Login;
